1	// Inline review payload builder. Validates findings against the diff,
2	// builds the GitHub reviews API comments[] array, and demotes strays.
3	
4	import { Eta } from "eta";
5	import { partitionFindings, indexDiff, defaultSide } from "./diff.js";
6	import { severityEmoji, findingPointer, projectPatch, formatConfidence } from "./surface.js";
7	import type { Finding, Findings } from "./schema.js";
8	import type { InlineComment, InlineResult } from "./types.js";
9	
10	/** Backtick-wrapped, `/`-joined model names for the disclosure line (issue #16), falling back to
11	 *  a plain phrase when no models are known. */
12	const formatModels = (models: readonly string[]): string =>
13	  models.length > 0 ? models.map((m) => `\`${m}\``).join("/") : "an AI model";
14	
15	/** Render a finding's inline comment body via the inline Eta template (bundled by default — see
16	 *  resolveInlineTemplatePath, index.ts). The template is the SSOT for all body text — severity
17	 *  header, description, recommendation, the projected patch block, and the [!TIP] disclosure fold;
18	 *  TS supplies only data. The patch is projected here (never a `suggestion` field — that field is
19	 *  gone as of schema 0.4). */
20	const renderCommentBody = (
21	  f: Finding,
22	  eta: Eta,
23	  template: string,
24	  modelsText: string,
25	  jsonUrl: string | undefined,
26	  pointer: string,
27	): string =>
28	  // Eta.renderString returns string | Promise<string>; with autoTrim:false it's always sync.
29	  // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-assertion
30	  eta.renderString(template, {
31	    ...f,
32	    patchProjection: projectPatch(f.patch),
33	    severityEmoji,
34	    formatConfidence,
35	    modelsText,
36	    jsonUrl: jsonUrl ?? null,
37	    findingsPointer: pointer,
38	  }) as string;
39	
40	/** Extra context threaded into each inline comment beyond the finding itself. */
41	export interface InlineContext {
42	  /** Eta template for each comment's body — bundled by default (index.ts's
43	   *  resolveInlineTemplatePath), overridable via --inline-template. */
44	  readonly inlineTemplate: string;
45	  /** Model name(s) that produced the review, for the template's disclosure line (issue #16). */
46	  readonly models?: readonly string[];
47	  /** Findings-json artifact URL — the marker's fallback when the embedded form is too large (#19). */
48	  readonly jsonUrl?: string;
49	  /** The full findings document — each in-diff comment embeds only its OWN finding (issue #31), but
50	   *  needs the document's `schema_version` to do so; omitted when the caller has no document at all
51	   *  (each comment's marker is then omitted too). */
52	  readonly findings?: Findings;
53	}
54	
55	/** Build the GitHub reviews API comments[] array from in-diff findings. Strays are demoted. */
56	export const buildInlineComments = (
57	  findings: readonly Finding[],
58	  diff: string,
59	  context: InlineContext,
60	): InlineResult => {
61	  const { inlineTemplate, models = [], jsonUrl, findings: fullFindings } = context;
62	  const index = indexDiff(diff);
63	  const { inDiff, strays } = partitionFindings(findings, index);
64	  const eta = new Eta({ autoTrim: false });
65	  const modelsText = formatModels(models);
66	
67	  const comments: InlineComment[] = inDiff.map((f) => {
68	    const pointer = fullFindings ? findingPointer(f, fullFindings.schema_version, jsonUrl) : "";
69	    const comment: InlineComment = {
70	      path: f.path,
71	      line: f.end_line,
72	      side: defaultSide(f.side),
73	      body: renderCommentBody(f, eta, inlineTemplate, modelsText, jsonUrl, pointer),
74	    };
75	    if (f.start_line < f.end_line) {
76	      return {
77	        ...comment,
78	        start_line: f.start_line,
79	        start_side: defaultSide(f.side),
80	      };
81	    }
82	    return comment;
83	  });
84	
85	  return { comments, strays, inDiff };
86	};
87	
88	/** Render the demoted (stray) findings as a markdown section for the summary. */
89	export const renderStraysSection = (strays: readonly Finding[]): string => {
90	  if (strays.length === 0) return "";
91	
92	  const items = strays.map(
93	    (f) => `- **${f.severity}** · \`${f.path}:${String(f.start_line)}\` — ${f.title}`,
94	  );
95	
96	  return [
97	    "",
98	    "---",
99	    "",
100	    "#### ⚠️ Findings on lines not in the diff (demoted to summary)",
101	    "",
102	    ...items,
103	  ].join("\n");
104	};
105

1	// Deterministic comment renderer. Takes findings + envelope + prices → comment markdown.
2	// Uses Eta templates; pure data-in, string-out — no side effects, no model invocation.
3	
4	import { Eta } from "eta";
5	import type { Finding, Severity } from "./schema.js";
6	import type { RenderInput, SeverityCounts } from "./types.js";
7	import { computeCost } from "./cost.js";
8	import { severityEmoji, findingsPointer, projectPatch, formatConfidence } from "./surface.js";
9	import type { PatchProjection } from "./surface.js";
10	
11	/** Escape pipe characters so they don't break markdown table columns. */
12	const escapePipes = (text: string): string => text.replace(/\|/g, "\\|");
13	
14	/** Replace backticks so they don't break inline code spans. */
15	const escapeCodeBackticks = (text: string): string => text.replace(/`/g, "-");
16	
17	/** A stray finding with its sanitized fields plus its projected patch block for the strays list. */
18	type StrayView = Finding & { readonly patchProjection: PatchProjection };
19	
20	/** Sanitize a stray finding's fields and attach its patch projection for the strays section. */
21	const sanitizeFinding = (f: Finding): StrayView => ({
22	  ...f,
23	  title: escapePipes(f.title),
24	  path: escapeCodeBackticks(f.path),
25	  patchProjection: projectPatch(f.patch),
26	});
27	
28	const emptySeverityCounts = (): Record<Severity, number> => ({
29	  critical: 0,
30	  major: 0,
31	  minor: 0,
32	  nit: 0,
33	});
34	
35	/** Tally findings by severity for the summary counts line. Ignores out-of-domain severities. */
36	export const computeSeverityCounts = (findings: readonly Finding[]): SeverityCounts =>
37	  findings.reduce<Record<Severity, number>>(
38	    (acc, f) => (f.severity in acc ? { ...acc, [f.severity]: acc[f.severity] + 1 } : acc),
39	    emptySeverityCounts(),
40	  );
41	
42	/** Render a code-review comment from findings, envelope, and prices. Pure. */
43	export const render = (input: RenderInput): string => {
44	  const eta = new Eta({ autoTrim: false });
45	  const usageAvailable = input.envelope !== null;
46	  const costReport = input.envelope ? computeCost(input.envelope.models, input.prices) : null;
47	  const pricesProvided = input.pricesProvided ?? true;
48	  const route = input.route ?? input.envelope?.route ?? null;
49	  const effort = input.effort ?? input.envelope?.effort ?? null;
50	  const modelNames = input.envelope ? input.envelope.models.map((m) => m.model).join(", ") : "";
51	
52	  return eta.renderString(input.template, {
53	    findings: input.findings,
54	    envelope: input.envelope,
55	    usageAvailable,
56	    costReport,
57	    pricesProvided,
58	    route,
59	    effort,
60	    modelNames,
61	    testReport: input.testReport ?? null,
62	    reviewedSha: input.reviewedSha ?? "0000000000000000000000000000000000000000",
63	    postedAt: input.postedAt ?? "",
64	    severityCounts: input.severityCounts ?? computeSeverityCounts(input.findings.findings),
65	    strays: (input.strays ?? []).map(sanitizeFinding),
66	    unanchoredCount: input.unanchoredCount ?? 0,
67	    inlineDisposition: input.inlineDisposition ?? null,
68	    runUrl: input.runUrl ?? null,
69	    jsonUrl: input.jsonUrl ?? null,
70	    findingsPointer: input.findingsPointer ?? findingsPointer(input.findings, input.jsonUrl),
71	    reviewUrl: input.reviewUrl ?? null,
72	    formatTokens: (n: number): string =>
73	      Number.isFinite(n) && n >= 0 ? n.toLocaleString("en-US") : "—",
74	    // Cost cells render N/A (never a false $0.00) when no real price map was provided — there are
75	    // real tokens spent, we simply have no rates to price them (SPEC §6.2).
76	    formatCost: (n: number): string =>
77	      !pricesProvided
78	        ? "N/A"
79	        : Number.isFinite(n)
80	          ? n > 0 && n.toFixed(2) === "0.00"
81	            ? "<$0.01"
82	            : `$${n.toFixed(2)}`
83	          : "—",
84	    formatDuration: (ms: number): string => {
85	      if (!Number.isFinite(ms) || ms < 0) return "—";
86	      const s = Math.round(ms / 1000);
87	      return s >= 60 ? `${String(Math.floor(s / 60))}m ${String(s % 60)}s` : `${String(s)}s`;
88	    },
89	    verdictBadge: (v: string): string => {
90	      switch (v) {
91	        case "approve":
92	          return "✅ approved";
93	        case "comment":
94	          return "💬 comment";
95	        case "changes":
96	          return "🔧 changes requested";
97	        default:
98	          return `❓ ${v}`;
99	      }
100	    },
101	    severityEmoji,
102	    formatConfidence,
103	  });
104	};
