5	  Finding,
6	  Findings,
7	  Side,
8	  Severity,
9	  ResultEnvelope,
10	  PriceMap,
11	  TestSummary,
12	} from "./schema.js";
13	
14	export interface InlineComment {
15	  readonly path: string;
16	  readonly line: number;
17	  readonly side: Side;
18	  readonly start_line?: number;
19	  readonly start_side?: Side;
20	  readonly body: string;
21	}
22	
23	export interface InlineResult {
24	  readonly comments: readonly InlineComment[];
25	  readonly strays: readonly Finding[];
26	  /** The in-diff findings the `comments` were built from — surfaced in the sticky (as extra strays)
27	   *  when the inline review can't be posted and falls back to body-only (issue #57). */
28	  readonly inDiff: readonly Finding[];
29	}
30	
31	export type SeverityCounts = Readonly<Record<Severity, number>>;
32	
33	/** What actually happened to the inline review, so the sticky's pointer states the truth (SPEC §5.1). */
34	export type InlineDisposition =
35	  | { readonly kind: "posted"; readonly count: number; readonly sha: string }
36	  | { readonly kind: "none-in-diff" }
37	  | { readonly kind: "inline-unavailable" }
38	  | { readonly kind: "no-envelope" };
39	
40	export interface RenderInput {
41	  readonly findings: Findings;
42	  /** null when the result envelope is unavailable or malformed — renders a "usage unavailable" note. */
43	  readonly envelope: ResultEnvelope | null;
44	  readonly prices: PriceMap;
45	  /** Whether `prices` is a real, caller-supplied price map (`true`) or the bundled all-zero example
46	   *  standing in for an absent one (`false`). An explicit signal the render layer is TOLD — never
47	   *  inferred from the map's contents or path — so cost renders as `N/A` (never a false `$0.00`)
48	   *  with a "no price map" footnote when absent (SPEC §6.2). Omitted ⇒ treated as provided. */
49	  readonly pricesProvided?: boolean;
50	  readonly template: string;
51	  readonly reviewedSha?: string;
52	  /** Preformatted UTC post time (e.g. "2026-07-07 18:42 UTC"), leading the sticky's "**Reviewed**
53	   *  `<sha>` at <postedAt>" meta segment (issue #28) — computed at the IO boundary (post.ts/CLI)
54	   *  via `formatUtc`, never here, so `render()` stays pure/clockless. Omitted ⇒ segment suppressed. */
55	  readonly postedAt?: string;
56	  /** Overrides the envelope's `route`/`effort` (SPEC §6.1) when set; otherwise the envelope is the source. */
57	  readonly route?: string;
58	  readonly effort?: string;
59	  readonly testReport?: TestSummary;
60	  /** Severity histogram for the summary counts line; derived from `findings` when omitted. */
61	  readonly severityCounts?: SeverityCounts;
62	  /** Findings that couldn't be anchored inline (SPEC §5.2 rule 1) — the sticky's only per-finding detail. */
63	  readonly strays?: readonly Finding[];
64	  /** How many of `strays` are in-diff findings whose inline comment GitHub rejected (issue #57),
65	   *  rather than genuinely out-of-diff. When > 0 the sticky titles the section "Findings" and adds a
